```

```typescript
function ajouterNote(
  releve: ReleveNotes,
  matricule: string,
  matiere: string,
  note: number
): void {
  if (!releve[matricule]) {
    releve[matricule] = {};
  }
  if (!releve[matricule][matiere]) {
    releve[matricule][matiere] = [];
  }
  releve[matricule][matiere].push(note);
}
```

```typescript
type NotesParMatiereRO = {
  readonly [matiere: string]: readonly number[];
};

type ReleveNotesRO = Record<string, NotesParMatiereRO>;
```
Cela empêche les modifications accidentelles des notes existantes.

